INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (1.47, "2023/09/22 14:59:59", "2023/06/30 12:00:00", 10001, 1, 1, "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！", 0.0, "クローチェ", -470.0, 2002, 1, 126401, 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (2.15, "2023/09/22 14:59:59", "2023/06/30 12:00:00", 10002, 2, 1, "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪", 0.0, "クローチェ", -470.0, 2002, 2, 126401, 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, "2023/09/22 14:59:59", "2023/06/30 12:00:00", 10003, 2, 1, "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", 0.0, "ライラエル", -470.0, 2002, 1, 126501, 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, "2023/09/22 14:59:59", "2023/06/30 12:00:00", 10004, 1, 1, "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", 0.0, "ライラエル", -470.0, 2002, 2, 126501, 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, "2023/12/22 14:59:59", "2023/09/15 15:00:00", 10005, 2, 2, "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", 0.0, "リンド", -470.0, 2002, 1, 127702, 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, "2023/12/22 14:59:59", "2023/09/15 15:00:00", 10006, 2, 2, "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", 0.0, "リンド", -470.0, 2002, 2, 127702, 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, "2023/12/22 14:59:59", "2023/09/15 15:00:00", 10007, 1, 2, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", 0.0, "ヴルム", -470.0, 2002, 1, 127802, 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (6.5, "2023/12/22 14:59:59", "2023/09/15 15:00:00", 10008, 2, 2, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", 0.0, "ヴルム", -470.0, 2002, 2, 127802, 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, "2024/03/22 14:59:59", "2023/12/15 15:00:00", 10009, 2, 3, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", 0.0, "アネモネ", -470.0, 2002, 1, 129602, 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, "2024/03/22 14:59:59", "2023/12/15 15:00:00", 10010, 2, 3, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", 0.0, "アネモネ", -470.0, 2002, 2, 129602, 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, "2024/03/22 14:59:59", "2023/12/15 15:00:00", 10011, 1, 3, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", 0.0, "ネフィ=ネラ", -470.0, 2002, 1, 129701, 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (6.2, "2024/03/22 14:59:59", "2023/12/15 15:00:00", 10012, 2, 3, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", 0.0, "ネフィ=ネラ", -470.0, 2002, 2, 129701, 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (3.1, "2024/06/22 14:59:59", "2024/03/15 15:00:00", 10013, 3, 4, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", 0.0, "カノン", -470.0, 2002, 1, 130301, 5);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (6.15, "2024/06/22 14:59:59", "2024/03/15 15:00:00", 10014, 3, 4, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", 0.0, "カノン", -470.0, 2002, 2, 130301, 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, "2024/06/22 14:59:59", "2024/03/15 15:00:00", 10015, 2, 4, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", 0.0, "ナーナ", -470.0, 2002, 1, 130401, 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (3.35, "2024/06/22 14:59:59", "2024/03/15 15:00:00", 10016, 2, 4, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", 0.0, "ナーナ", -470.0, 2002, 2, 130401, 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, "2024/09/22 14:59:59", "2024/06/15 15:00:00", 10017, 1, 5, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", 0.0, "ホウオウ", -470.0, 2002, 1, 130502, 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (3.18, "2024/09/22 14:59:59", "2024/06/15 15:00:00", 10018, 2, 5, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", 0.0, "ホウオウ", -470.0, 2002, 2, 130502, 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, "2024/09/22 14:59:59", "2024/06/15 15:00:00", 10019, 4, 5, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", 0.0, "ホウオウ", -470.0, 2002, 3, 130503, 4);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (4.9, "2024/09/22 14:59:59", "2024/06/15 15:00:00", 10020, 1, 5, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", 0.0, "ネア", -470.0, 2002, 1, 123301, 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (4.8, "2024/09/22 14:59:59", "2024/06/15 15:00:00", 10021, 1, 5, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", 0.0, "ネア", -470.0, 2002, 2, 123301, 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (4.922, "2024/12/22 14:59:59", "2024/09/15 15:00:00", 10022, 3, 6, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", 0.0, "カリザ", -470.0, 2002, 1, 133301, 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (9.638, "2024/12/22 14:59:59", "2024/09/15 15:00:00", 10023, 3, 6, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", 0.0, "カリザ", -470.0, 2002, 2, 133301, 5);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (2.88, "2024/12/22 14:59:59", "2024/09/15 15:00:00", 10024, 1, 6, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", 0.0, "ミーア", -470.0, 2002, 1, 133401, 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (4.818, "2024/12/22 14:59:59", "2024/09/15 15:00:00", 10025, 5, 6, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", 0.0, "ミーア", -470.0, 2002, 2, 133401, 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (1.78, "2025/03/22 14:59:59", "2024/12/15 15:00:00", 10026, 2, 7, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", 0.0, "グレイス", -470.0, 2002, 1, 133002, 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (6.15, "2025/03/22 14:59:59", "2024/12/15 15:00:00", 10027, 1, 7, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", 0.0, "グレイス", -470.0, 2002, 2, 133002, 7);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (4.28, "2025/03/22 14:59:59", "2024/12/15 15:00:00", 10028, 6, 7, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", 0.0, "ヴァイオレット", -470.0, 2002, 1, 133102, 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, "2025/03/22 14:59:59", "2024/12/15 15:00:00", 10029, 1, 7, "じめじめした商品は\nございませんので\n安心してお買い求め下さい", 0.0, "ヴァイオレット", -470.0, 2002, 2, 133102, 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (5.53, "2025/06/23 14:59:59", "2025/03/15 15:00:00", 10030, 2, 8, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", 0.0, "ルルィ", -470.0, 2002, 1, 136902, 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (6.05, "2025/06/23 14:59:59", "2025/03/15 15:00:00", 10031, 9, 8, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", 0.0, "ルルィ", -470.0, 2002, 2, 136902, 7);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, "2025/06/23 14:59:59", "2025/03/15 15:00:00", 10032, 2, 8, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", 0.0, "デュラン", -470.0, 2002, 1, 137001, 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, "2025/06/23 14:59:59", "2025/03/15 15:00:00", 10033, 2, 8, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", 0.0, "デュラン", -470.0, 2002, 2, 137001, 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, "2025/09/23 14:59:59", "2025/06/16 15:00:00", 10034, 2, 9, "おう\n好きなもん持ってきな", 0.0, "サツキ", -470.0, 2002, 1, 135902, 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (4.935, "2025/09/23 14:59:59", "2025/06/16 15:00:00", 10035, 1, 9, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", 0.0, "サツキ", -470.0, 2002, 2, 135902, 6);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (7.441, "2025/09/23 14:59:59", "2025/06/16 15:00:00", 10036, 2, 9, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", 0.0, "ユキノ", -470.0, 2002, 1, 135802, 5);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, "2025/09/23 14:59:59", "2025/06/16 15:00:00", 10037, 7, 9, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", 0.0, "ユキノ", -470.0, 2002, 2, 135802, 7);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (2.295, "2025/12/22 14:59:59", "2025/09/16 15:00:00", 10038, 2, 10, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", 0.0, "クルル", -470.0, 2002, 1, 130901, 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (6.281, "2025/12/22 14:59:59", "2025/09/16 15:00:00", 10039, 1, 10, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", 0.0, "クルル", -470.0, 2002, 2, 130901, 6);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (5.549, "2025/12/22 14:59:59", "2025/09/16 15:00:00", 10040, 2, 10, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", 0.0, "ヴォルガーノ", -470.0, 2002, 1, 137701, 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (2.64, "2025/12/22 14:59:59", "2025/09/16 15:00:00", 10041, 3, 10, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", 0.0, "ヴォルガーノ", -470.0, 2002, 2, 137701, 6);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (7.642, "2026/03/23 11:59:59", "2025/12/15 15:00:00", 10042, 7, 11, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", 0.0, "ライラエル", -470.0, 2002, 1, 132801, 4);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, "2026/03/23 11:59:59", "2025/12/15 15:00:00", 10043, 1, 11, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", 0.0, "ライラエル", -470.0, 2002, 2, 132802, 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, "2026/03/23 11:59:59", "2025/12/15 15:00:00", 10044, 1, 11, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", 0.0, "クローチェ", -470.0, 2002, 1, 134502, 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (3.72, "2026/03/23 11:59:59", "2025/12/15 15:00:00", 10045, 2, 11, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", 0.0, "クローチェ", -470.0, 2002, 2, 134501, 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (4.991, "2026/06/22 11:59:59", "2026/03/16 12:00:00", 10046, 2, 12, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", 0.0, "ネフィ＝ネラ", -470.0, 2002, 1, 138201, 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (3.877, "2026/06/22 11:59:59", "2026/03/16 12:00:00", 10047, 1, 12, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", 0.0, "ネフィ＝ネラ", -470.0, 2002, 2, 138201, 4);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (1.71, "2026/06/22 11:59:59", "2026/03/16 12:00:00", 10048, 4, 12, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", 0.0, "アラクネ", -470.0, 2002, 1, 136001, 6);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (5.32, "2026/06/22 11:59:59", "2026/03/16 12:00:00", 10049, 5, 12, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", 0.0, "アラクネ", -470.0, 2002, 2, 136001, 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (3.727, "2026/09/22 11:59:59", "2026/06/15 12:00:00", 10050, 9, 13, "水着で、店番とか──\n本当、意味がわかりません\n海の家でもないのに…", 0.0, "アネモネ", -470.0, 2002, 1, 135401, 4);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (7.213, "2026/09/22 11:59:59", "2026/06/15 12:00:00", 10051, 7, 13, "──リアみたいに、\nもっと愛想良い接客を…\nいえ──なんでもないです", 0.0, "アネモネ", -470.0, 2002, 2, 135401, 9);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (1.874, "2026/09/22 11:59:59", "2026/06/15 12:00:00", 10052, 1, 13, "いらっしゃいませー♪\n奉仕活動兼、将来のために\nたくさん働いちゃいます♪", 0.0, "クリア", -470.0, 2002, 1, 135301, 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, "2026/09/22 11:59:59", "2026/06/15 12:00:00", 10053, 2, 13, "アルバイトが終わったら\n海に遊びに行きましょう！\nモネちゃんも一緒に♪", 0.0, "クリア", -470.0, 2002, 2, 135301, 2);
